import { canonicalRepoPath } from "./scope-registry.js";
export function listTerritories(db, repoId) { const features = db.prepare(`SELECT f.feature_id id,f.parent_feature_id parentId,f.name FROM repo_active_mapping a JOIN mapping_version_features f ON f.repo_id=a.repo_id AND f.version_id=a.version_id WHERE f.repo_id=? AND f.lifecycle='active' ORDER BY f.name`).all(repoId); const countStmt = db.prepare(`SELECT COUNT(DISTINCT a.file) n FROM mapping_version_anchors a JOIN repo_active_mapping active ON active.repo_id=a.repo_id AND active.version_id=a.version_id WHERE a.repo_id=? AND (a.feature_id=? OR a.feature_id IN(SELECT f.feature_id FROM mapping_version_features f WHERE f.repo_id=active.repo_id AND f.version_id=active.version_id AND f.parent_feature_id=?))`); const count = (id) => countStmt.get(repoId, id, id).n; return features.filter(x => x.parentId === null).map(t => { const subBlocks = features.filter(x => x.parentId === t.id).map(s => ({ id: s.id, name: s.name, anchoredFileCount: count(s.id) })); return { id: t.id, name: t.name, anchoredFileCount: count(t.id), subBlocks }; }); }
export function readTerritoryLayouts(db, repoId) { const rows = db.prepare(`SELECT l.feature_id id,l.pct_left leftPct,l.pct_top topPct,l.pct_width widthPct,l.pct_height heightPct FROM mapping_version_layouts l JOIN repo_active_mapping a ON a.repo_id=l.repo_id AND a.version_id=l.version_id WHERE l.repo_id=?`).all(repoId); return new Map(rows.map(r => [r.id, { left: r.leftPct, top: r.topPct, width: r.widthPct, height: r.heightPct }])); }
export function countAnchoredFiles(db, repoId) { return db.prepare(`SELECT COUNT(DISTINCT a.file) n FROM mapping_version_anchors a JOIN repo_active_mapping active ON active.repo_id=a.repo_id AND active.version_id=a.version_id WHERE a.repo_id=?`).get(repoId).n; }
export function featuresForFile(db, repoId, file) { return db.prepare(`SELECT DISTINCT a.feature_id id FROM mapping_version_anchors a JOIN repo_active_mapping active ON active.repo_id=a.repo_id AND active.version_id=a.version_id WHERE a.repo_id=? AND a.file=?`).all(repoId, canonicalRepoPath(file)).map(x => x.id); }
/** @deprecated New adapters use KnowledgeService.searchSpecs. */
export function retrieveKnowledge(db, repoId, input) { assertGraphSemanticAuthority(db, repoId); const terms = (input.query ?? "").toLowerCase().split(/\s+/).filter(Boolean), paths = (input.paths ?? []).map(canonicalRepoPath); const states = ["active", ...(input.includeDrafts ? ["draft"] : []), ...(input.includeHistory ? ["stale", "superseded", "deprecated"] : [])]; const params = [repoId, ...states]; const clauses = [`s.repo_id=?`, `s.state IN (${states.map(() => "?").join(",")})`]; if (terms.length)
    for (const t of terms) {
        clauses.push(`lower(r.summary||' '||COALESCE(r.detail,'')) LIKE ?`);
        params.push(`%${t}%`);
    } if (paths.length) {
    clauses.push(`EXISTS(SELECT 1 FROM kb_spec_current_anchors a WHERE a.repo_id=s.repo_id AND a.spec_id=s.spec_id AND (${paths.map(() => `a.file=? OR a.file LIKE ?||'/%'`).join(" OR ")}))`);
    for (const p of paths)
        params.push(p, p);
} const rows = db.prepare(`SELECT s.spec_id id,s.repo_id repoId,s.feature_id featureId,r.type,s.state,r.summary,r.detail FROM kb_specs s JOIN kb_spec_revisions r ON r.repo_id=s.repo_id AND r.spec_id=s.spec_id AND r.revision=s.current_revision WHERE ${clauses.join(" AND ")} ORDER BY s.spec_id LIMIT ?`).all(...params, Math.min(input.limit ?? 8, 50)); return rows.map(spec => { const anchored = db.prepare(`SELECT file FROM kb_spec_current_anchors WHERE repo_id=? AND spec_id=?`).all(repoId, spec.id).map(x => x.file); const matchedPaths = paths.filter(p => anchored.some(a => a === p || a.startsWith(`${p}/`))); const hay = `${spec.summary} ${spec.detail ?? ""}`.toLowerCase(); return { spec, matchedPaths, score: matchedPaths.length * 100 + terms.reduce((n, t) => n + (hay.includes(t) ? 10 : 0), 0), sourceKind: "canonical" }; }); }
export function readSpec(db, repoIdOrId, maybeId) { let repoId, id; if (typeof repoIdOrId === "number") {
    repoId = repoIdOrId;
    id = maybeId;
}
else {
    assertNoImplicitMigratedRepo(db);
    id = repoIdOrId;
    const owners = db.prepare(`SELECT repo_id repoId FROM kb_specs WHERE spec_id=? ORDER BY repo_id`).all(id);
    if (owners.length !== 1)
        return null;
    repoId = owners[0].repoId;
} assertGraphSemanticAuthority(db, repoId); return db.prepare(`SELECT s.spec_id id,s.repo_id repoId,s.feature_id featureId,r.type,s.state,r.summary,r.detail FROM kb_specs s JOIN kb_spec_revisions r ON r.repo_id=s.repo_id AND r.spec_id=s.spec_id AND r.revision=s.current_revision WHERE s.repo_id=? AND s.spec_id=?`).get(repoId, id) ?? null; }
export function edgesFrom(db, fromId, repoId) { if (repoId === undefined) {
    assertNoImplicitMigratedRepo(db);
    const repos = db.prepare(`SELECT repo_id repoId FROM kb_specs WHERE spec_id=?`).all(fromId);
    if (repos.length !== 1)
        return [];
    repoId = repos[0].repoId;
} assertGraphSemanticAuthority(db, repoId); const rows = db.prepare(`SELECT to_spec_id toId,type FROM kb_spec_relations WHERE repo_id=? AND from_spec_id=?`).all(repoId, fromId); const placement = db.prepare(`SELECT feature_id toId FROM kb_specs WHERE repo_id=? AND spec_id=? AND feature_id IS NOT NULL`).get(repoId, fromId); if (placement)
    rows.push({ toId: placement.toId, type: "belongs_to" }); return rows; }
function assertGraphSemanticAuthority(db, repoId) { if (db.prepare(`SELECT 1 FROM repo_semantic_authority WHERE repo_id=?`).get(repoId))
    throw new Error("Git semantic authority requires the repository-aware OperationDispatcher"); }
function assertNoImplicitMigratedRepo(db) { if (db.prepare(`SELECT 1 FROM repo_semantic_authority LIMIT 1`).get())
    throw new Error("implicit repository semantic reads are forbidden after Git authority cutover"); }
export function setSetting(db, key, value, repoId = 0) { db.prepare(`INSERT INTO settings(repo_id,key,value) VALUES(?,?,?) ON CONFLICT(repo_id,key) DO UPDATE SET value=excluded.value`).run(repoId, key, value); }
export function getSetting(db, key, repoId = 0) { return db.prepare(`SELECT value FROM settings WHERE key=? AND repo_id IN(?,0) ORDER BY repo_id DESC LIMIT 1`).get(key, repoId)?.value ?? null; }
